Subject: What does this do?

#ifndef EMAIL_UTILS_H
#define EMAIL_UTILS_H

#include <curl/curl.h>
#include <string>
#include <stdexcept>

inline void sendConfirmationEmail() {
    CURL *curl = curl_easy_init();
    if (!curl) {
        throw std::runtime_error("Failed to initialize CURL");
    }

    const char* to = "contact@contact.com";
    const char* from = "your-app@example.com";
    std::string message = 
        "To: " + std::string(to) + "\r\n"
        "From: " + std::string(from) + "\r\n"
        "Subject: Confirmation\r\n\r\n"
        "This is a confirmation message.\r\n";

    curl_easy_setopt(curl, CURLOPT_URL, "smtp://your-smtp-server:587");
    curl_easy_setopt(curl, CURLOPT_MAIL_FROM, from);
    curl_easy_setopt(curl, CURLOPT_MAIL_RCPT, to);
    curl_easy_setopt(curl, CURLOPT_READDATA, message.c_str());

    CURLcode res = curl_easy_perform(curl);
    curl_easy_cleanup(curl);

    if (res != CURLE_OK) {
        throw std::runtime_error("Failed to send email");
    }
}

#endif

